using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed — Cosmos DB indexing is managed via the container's
        // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
        // In EF Core 9 calling HasIndex on a Cosmos entity throws at startup.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Preserve "Discriminator" property name used by existing 500K documents.
            // EF Core 9 defaults to "$type"; without this, queries and direct SQL
            // referencing c.Discriminator will break.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve the EF Core 8 compound id format ("Product|123").
            // EF Core 9 defaults to key-only ids ("123"); without this,
            // FindAsync and point-reads against existing documents will fail.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

