using Microsoft.EntityFrameworkCore;
using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports sync I/O — use async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // via HasDiscriminator<string>("Discriminator") in the model config.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync .ToList() throws in EF Core 9 Cosmos; use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

